359→export function disposeIfDisposable<T extends IDisposable | object>(disposables: Array<T>): Array<T> {
360→	for (const d of disposables) {
361→		if (isDisposable(d)) {
362→			d.dispose();
363→		}
364→	}
365→	return [];
366→}
