 54→			} else if (isDisposable(value)) {
 55→				// promise has been cancelled, result is disposable and will
 56→				// be cleaned up
 57→				value.dispose();
 58→			}
 59→		}, err => {
 60→			subscription.dispose();
 61→			source.dispose();
 62→			reject(err);
 63→		});
 64→	});
