382→export class Delayer<T> implements IDisposable {
383→
384→	private deferred: IScheduledLater | null;
385→	private completionPromise: Promise<any> | null;
386→	private doResolve: ((value?: any | Promise<any>) => void) | null;
387→	private doReject: ((err: unknown) => void) | null;
388→	private task: ITask<T | Promise<T>> | null;
