708→
709→	constructor(maxDegreeOfParalellism: number) {
710→		this.maxDegreeOfParalellism = maxDegreeOfParalellism;
711→		this.outstandingPromises = [];
712→		this.runningPromises = 0;
713→		this._onDrained = new Emitter<void>();
714→	}
715→
716→	/**
717→	 *
718→	 * @returns A promise that resolved when all work is done (onDrained) or when
719→	 * there is nothing to do
720→	 */
721→	whenIdle(): Promise<void> {
722→		return this.size > 0
723→			? Event.toPromise(this.onDrained)
724→			: Promise.resolve();
725→	}
726→
727→	get onDrained(): Event<void> {
728→		return this._onDrained.event;
729→	}
730→
731→	get size(): number {
732→		return this._size;
733→	}
734→
735→	queue(factory: ITask<Promise<T>>): Promise<T> {
736→		if (this._isDisposed) {
737→			throw new Error('Object has been disposed');
738→		}
739→		this._size++;
740→
741→		return new Promise<T>((c, e) => {
742→			this.outstandingPromises.push({ factory, c, e });
743→			this.consume();
744→		});
745→	}
746→
747→	private consume(): void {
748→		while (this.outstandingPromises.length && this.runningPromises < this.maxDegreeOfParalellism) {
749→			const iLimitedTask = this.outstandingPromises.shift()!;
750→			this.runningPromises++;
751→
752→			const promise = iLimitedTask.factory();
753→			promise.then(iLimitedTask.c, iLimitedTask.e);
754→			promise.then(() => this.consumed(), () => this.consumed());
755→		}
756→	}
757→
758→	private consumed(): void {
759→		if (this._isDisposed) {
760→			return;
761→		}
762→		this.runningPromises--;
763→		if (--this._size === 0) {
764→			this._onDrained.fire();
765→		}
766→
767→		if (this.outstandingPromises.length > 0) {
768→			this.consume();
769→		}
770→	}
771→
772→	clear(): void {
773→		if (this._isDisposed) {
774→			throw new Error('Object has been disposed');
775→		}
776→		this.outstandingPromises.length = 0;
777→		this._size = this.runningPromises;
778→	}
779→
780→	dispose(): void {
781→		this._isDisposed = true;
782→		this.outstandingPromises.length = 0; // stop further processing
783→		this._size = 0;
784→		this._onDrained.dispose();
785→	}
786→}
