export class Limiter<T> implements ILimiter<T> {
	private _size = 0;
	private runningPromises: number;
	private readonly maxDegreeOfParallelism: number;
	private readonly outstandingPromises: ILimitedTaskFactory<T>[];
	private readonly _onDrained: Emitter<void>;

	queue(factory: ITask<Promise<T>>): Promise<T> {
		if (this._isDisposed) throw new Error('Object has been disposed');
		this._size++;

		return new Promise<T>((c, e) => {
			this.outstandingPromises.push({ factory, c, e });
			this.consume();
		});
	}

	private consume(): void {
		while (this.outstandingPromises.length && this.runningPromises < this.maxDegreeOfParallelism) {
			const iLimitedTask = this.outstandingPromises.shift()!;
			this.runningPromises++;

			const promise = iLimitedTask.factory();
			promise.then(iLimitedTask.c, iLimitedTask.e);
			promise.then(() => this.consumed(), () => this.consumed());
		}
	}

	private consumed(): void {
		if (this._isDisposed) return;
		this.runningPromises--;
		if (--this._size === 0) {
			this._onDrained.fire();
		}
		if (this.outstandingPromises.length > 0) {
			this.consume();
		}
	}
}

