```typescript
export interface CancelablePromise<T> extends Promise<T> {
	cancel(): void;
}

export function createCancelablePromise<T>(callback: (token: CancellationToken) => Promise<T>): CancelablePromise<T> {
	const source = new CancellationTokenSource();
	const thenable = callback(source.token);
	let isCancelled = false;

	const promise = new Promise<T>((resolve, reject) => {
		const subscription = source.token.onCancellationRequested(() => {
			isCancelled = true;
			subscription.dispose();
			reject(new CancellationError());
		});
		Promise.resolve(thenable).then(value => {
			subscription.dispose();
			source.dispose();
			if (!isCancelled) {
				resolve(value);
			} else if (isDisposable(value)) {
				// Automatically dispose result if cancelled
				value.dispose();
			}
		}, err => {
			subscription.dispose();
			source.dispose();
			reject(err);
		});
	});

	return <CancelablePromise<T>>new class {
		cancel() {
			source.cancel();
			source.dispose();
		}
		then<TResult1 = T, TResult2 = never>(resolve?: ..., reject?: ...): Promise<TResult1 | TResult2> {
			return promise.then(resolve, reject);
		}
		catch<TResult = never>(reject?: ...): Promise<T | TResult> {
			return this.then(undefined, reject);
		}
		finally(onfinally?: ...): Promise<T> {
			return promise.finally(onfinally);
		}
	};
}
```

**Key Integration Points:**
- Extends Promise for seamless chaining
- Wraps a `CancellationTokenSource` to propagate cancellation
- **Automatic cleanup:** If result is `IDisposable`, it's disposed on cancellation
- Tracks cancellation state to avoid double resolution

