export interface CancellationToken {
	readonly isCancellationRequested: boolean;
	readonly onCancellationRequested: (
		listener: (e: void) => unknown, 
		thisArgs?: unknown, 
		disposables?: IDisposable[]
	) => IDisposable;
}

class MutableToken implements CancellationToken {
	private _isCancelled: boolean = false;
	private _emitter: Emitter<void> | null = null;

	public cancel() {
		if (!this._isCancelled) {
			this._isCancelled = true;
			if (this._emitter) {
				this._emitter.fire(undefined);
				this.dispose();
			}
		}
	}

	get isCancellationRequested(): boolean {
		return this._isCancelled;
	}

	get onCancellationRequested(): Event<void> {
		if (this._isCancelled) {
			return shortcutEvent; // Fire immediately if already cancelled
		}
		if (!this._emitter) {
			this._emitter = new Emitter<void>();
		}
		return this._emitter.event;
	}

	public dispose(): void {
		if (this._emitter) {
			this._emitter.dispose();
			this._emitter = null;
		}
	}
}

export class CancellationTokenSource {
	private _token?: CancellationToken = undefined;
	private _parentListener?: IDisposable = undefined;

	constructor(parent?: CancellationToken) {
		this._parentListener = parent && parent.onCancellationRequested(this.cancel, this);
	}

	get token(): CancellationToken {
		if (!this._token) {
			this._token = new MutableToken();
		}
		return this._token;
	}

	cancel(): void {
		if (!this._token) {
			this._token = CancellationToken.Cancelled; // Lazy: save object allocation
		} else if (this._token instanceof MutableToken) {
			this._token.cancel();
		}
	}

	dispose(cancel: boolean = false): void {
		if (cancel) {
			this.cancel();
		}
		this._parentListener?.dispose();
		if (!this._token) {
			this._token = CancellationToken.None;
		} else if (this._token instanceof MutableToken) {
			this._token.dispose();
		}
	}
}

export class CancellationTokenPool {
	// Aggregates multiple tokens, fires pool token only after ALL child tokens cancelled
	private _total: number = 0;
	private _cancelled: number = 0;

	add(token: CancellationToken): void {
		if (this._isDone) return;
		this._total++;
		if (token.isCancellationRequested) {
			this._cancelled++;
			this._check();
			return;
		}
		const d = token.onCancellationRequested(() => {
			d.dispose();
			this._cancelled++;
			this._check();
		});
		this._listeners.add(d);
	}

	private _check(): void {
		if (!this._isDone && this._total > 0 && this._total === this._cancelled) {
			this._isDone = true;
			this._listeners.dispose();
			this._source.cancel();
		}
	}
}
```

**Key Patterns:**
- **Lazy initialization:** Token only created when needed
- **Propagation chain:** Parent token can trigger child cancellation
- **Event-driven:** Uses `Emitter<void>` to signal cancellation
- **Singleton optimization:** `CancellationToken.None` and `.Cancelled` are frozen singletons
- **Pool aggregation:** Multiple tokens can be combined with conditional cancellation

