```typescript
export interface IDisposable {
	dispose(): void;
}

export class DisposableStore implements IDisposable {
	private readonly _toDispose = new Set<IDisposable>();
	private _isDisposed = false;

	public dispose(): void {
		if (this._isDisposed) return;
		markAsDisposed(this);
		this._isDisposed = true;
		this.clear();
	}

	public add<T extends IDisposable>(o: T): T {
		if (!o || o === Disposable.None) return o;
		setParentOfDisposable(o, this);
		if (this._isDisposed) {
			console.warn(new Error('Adding to disposed store, object will leak!').stack);
		} else {
			this._toDispose.add(o);
		}
		return o;
	}

	public delete<T extends IDisposable>(o: T): void {
		if (!o) return;
		this._toDispose.delete(o);
		o.dispose();
	}

	public clear(): void {
		try {
			dispose(this._toDispose);
		} finally {
			this._toDispose.clear();
		}
	}
}

export abstract class Disposable implements IDisposable {
	static readonly None = Object.freeze<IDisposable>({ dispose() { } });
	protected readonly _store = new DisposableStore();

	constructor() {
		trackDisposable(this);
		setParentOfDisposable(this._store, this);
	}

	public dispose(): void {
		markAsDisposed(this);
		this._store.dispose();
	}

	protected _register<T extends IDisposable>(o: T): T {
		return this._store.add(o);
	}
}

export class MutableDisposable<T extends IDisposable> implements IDisposable {
	private _value?: T;
	private _isDisposed = false;

	get value(): T | undefined {
		return this._isDisposed ? undefined : this._value;
	}

	set value(value: T | undefined) {
		if (this._isDisposed || value === this._value) return;
		this._value?.dispose();
		if (value) {
			setParentOfDisposable(value, this);
		}
		this._value = value;
	}

	clear(): void {
		this.value = undefined;
	}

	clearAndLeak(): T | undefined {
		const oldValue = this._value;
		this._value = undefined;
		if (oldValue) {
			setParentOfDisposable(oldValue, null); // Unparent for leak
		}
		return oldValue;
	}

	dispose(): void {
		this._isDisposed = true;
		this._value?.dispose();
		this._value = undefined;
	}
}

export class DisposableMap<K, V extends IDisposable = IDisposable> implements IDisposable {
	private readonly _store: Map<K, V>;

	set(key: K, value: V): void {
		if (!skipDisposeOnOverwrite) {
			this._store.get(key)?.dispose(); // Auto-cleanup old value
		}
		this._store.set(key, value);
		setParentOfDisposable(value, this);
	}

	deleteAndDispose(key: K): void {
		this._store.get(key)?.dispose();
		this._store.delete(key);
	}

	deleteAndLeak(key: K): V | undefined {
		const value = this._store.get(key);
		if (value) {
			setParentOfDisposable(value, null);
		}
		this._store.delete(key);
		return value;
	}
}
```

