export class Delayer<T> implements IDisposable {
	private deferred: IScheduledLater | null;
	private completionPromise: Promise<any> | null;

	trigger(task: ITask<T | Promise<T>>, delay = this.defaultDelay): Promise<T> {
		this.task = task;
		this.cancelTimeout();

		if (!this.completionPromise) {
			this.completionPromise = new Promise((resolve, reject) => {
				this.doResolve = resolve;
				this.doReject = reject;
			}).then(() => {
				this.completionPromise = null;
				if (this.task) {
					const task = this.task;
					this.task = null;
					return task();
				}
				return undefined;
			});
		}

		const fn = () => {
			this.deferred = null;
			this.doResolve?.(null);
		};

		this.deferred = delay === MicrotaskDelay 
			? microtaskDeferred(fn) 
			: timeoutDeferred(delay, fn);

		return this.completionPromise;
	}

	dispose(): void {
		this.cancel();
	}
}

export class ThrottledDelayer<T> {
	private delayer: Delayer<Promise<T>>;
	private throttler: Throttler;

	trigger(promiseFactory: ICancellableTask<Promise<T>>, delay?: number): Promise<T> {
		return this.delayer.trigger(() => this.throttler.queue(promiseFactory), delay) as unknown as Promise<T>;
	}
}
